import pytest
from typing import Dict, List

def topological_sort(graph: Dict) -> List:
    visited = set()
    result = []
    def dfs(node):
        if node in visited:
            return
        visited.add(node)
        for neighbor in graph.get(node, []):
            dfs(neighbor)
        result.append(node)
    for node in graph:
        dfs(node)
    return result[::-1]

def is_valid_topological_order(graph: Dict, order: List) -> bool:
    """Helper to check if the order is a valid topological sort."""
    if len(order) != len(graph):
        return False
    pos = {node: i for i, node in enumerate(order)}
    for node in graph:
        for neighbor in graph.get(node, []):
            if pos[node] >= pos[neighbor]:
                return False
    return True

class TestTopologicalSort:
    def test_happy_path_simple_dag(self):
        graph = {'A': ['B'], 'B': ['C'], 'C': []}
        result = topological_sort(graph)
        assert is_valid_topological_order(graph, result)

    def test_empty_graph(self):
        graph = {}
        result = topological_sort(graph)
        assert result == []

    def test_single_node(self):
        graph = {'A': []}
        result = topological_sort(graph)
        assert result == ['A']

    def test_no_edges(self):
        graph = {'A': [], 'B': []}
        result = topological_sort(graph)
        assert set(result) == {'A', 'B'}
        # Since order can vary for disconnected, just check all nodes are present

    def test_disconnected_graph(self):
        graph = {'A': ['B'], 'B': [], 'C': ['D'], 'D': []}
        result = topological_sort(graph)
        assert is_valid_topological_order(graph, result)

    def test_linear_chain(self):
        graph = {'1': ['2'], '2': ['3'], '3': ['4'], '4': []}
        result = topological_sort(graph)
        assert result == ['1', '2', '3', '4']

    def test_multiple_dependencies(self):
        graph = {'A': ['C', 'D'], 'B': ['D'], 'C': ['E'], 'D': ['E'], 'E': []}
        result = topological_sort(graph)
        assert is_valid_topological_order(graph, result)

    def test_cycle_invalid_order(self):
        graph = {'A': ['B'], 'B': ['A']}
        result = topological_sort(graph)
        # For cyclic graph, the result won't be a valid topological order
        assert not is_valid_topological_order(graph, result)

    def test_graph_not_dict(self):
        with pytest.raises(TypeError):
            topological_sort("not a dict")

    def test_values_not_iterable(self):
        graph = {'A': 'B'}  # Value is string, not iterable
        with pytest.raises(TypeError):
            topological_sort(graph)

    def test_nodes_not_hashable(self):
        graph = {['A']: []}  # List as key, not hashable
        with pytest.raises(TypeError):
            topological_sort(graph)

    def test_neighbor_not_in_graph(self):
        graph = {'A': ['B'], 'C': []}  # B not in graph keys
        result = topological_sort(graph)
        # Should still work, as B is visited but not in graph
        assert 'A' in result and 'C' in result
        # B might be in result if it's added during DFS
        # Actually, since B is not in graph.keys(), DFS starts from A and C, visits B, adds B and A and C
        # result will have B, A, C or similar
        assert len(result) == 3  # A, B, C
